    int m = grid.size();
    int n = grid[0].size();

    // Create a copy of the grid to avoid modifying the original
    std::vector<std::vector<long long>> result = grid;

    // Extract the submatrix
    std::vector<std::vector<long long>> submatrix(k, std::vector<long long>(k));
    for (int i = 0; i < k; ++i) {
        for (int j = 0; j < k; ++j) {
            submatrix[i][j] = grid[x + i][y + j];
        }
    }

    // Vertical flip the submatrix
    for (int i = 0; i < k / 2; ++i) {
        std::swap(submatrix[i][0], submatrix[k - 1 - i][0]);
        std::swap(submatrix[i][1], submatrix[k - 1 - i][1]);
        std::swap(submatrix[i][2], submatrix[k - 1 - i][2]);
        // Add more swaps for other columns if needed
    }

    // Put the flipped submatrix back into the result
    for (int i = 0; i < k; ++i) {
        for (int j = 0; j < k; ++j) {
            result[x + i][y + j] = submatrix[i][j];
        }
    }

    return result;
}

